{
  "schema": "brainflow.procedure.v1",
  "name": "windows_arglen_policy",
  "description": "On Windows, avoid long CLI argument payloads; write large JSON/text to temp files and pass file paths instead.",
  "rules": [
    {
      "when": "platform == 'windows' && payload_length > 6000",
      "action": "write_payload_to_temp_file_and_pass_path"
    }
  ]
}
